{"content":""use client";

import { useEffect, useRef } from "react";

export type CanvasState = "idle" | "thinking" | "responding";

interface Particle {
  x: number; y: number;
  vx: number; vy: number;
  size: number;
  opacity: number;
  rgb: string;
  phase: number;
  phaseSpeed: number;
}

interface FieldLine {
  pts: number[];   // x0,y0, cx1,cy1, cx2,cy2, x1,y1
  vel: number[];   // dx for each control point
  opacity: number;
}

function hex(h: string): string {
  const r = parseInt(h.slice(1, 3), 16);
  const g = parseInt(h.slice(3, 5), 16);
  const b = parseInt(h.slice(5, 7), 16);
  return `${r},${g},${b}`;
}

const COLORS = ["#3b4fd8", "#6d4ff5", "#9b7cfa", "#c4b5fd", "#818cf8"].map(hex);

export default function OmegaCanvas({ state }: { state: CanvasState }) {
  const ref = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let raf: number;
    let W = 0, H = 0;
    let frame = 0;

    const resize = () => {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    };
    window.addEventListener("resize", resize);
    resize();

    // Particles
    const COUNT = 140;
    const particles: Particle[] = Array.from({ length: COUNT }, () => ({
      x: Math.random() * W,
      y: Math.random() * H,
      vx: (Math.random() - 0.5) * 0.35,
      vy: (Math.random() - 0.5) * 0.35,
      size: Math.random() * 1.8 + 0.4,
      opacity: Math.random() * 0.55 + 0.1,
      rgb: COLORS[Math.floor(Math.random() * COLORS.length)],
      phase: Math.random() * Math.PI * 2,
      phaseSpeed: 0.008 + Math.random() * 0.018,
    }));

    // Field lines
    const LINES = 10;
    const lines: FieldLine[] = Array.from({ length: LINES }, () => ({
      pts: [
        Math.random() * W, Math.random() * H,
        Math.random() * W, Math.random() * H,
        Math.random() * W, Math.random() * H,
        Math.random() * W, Math.random() * H,
      ],
      vel: Array.from({ length: 8 }, () => (Math.random() - 0.5) * 0.25),
      opacity: Math.random() * 0.07 + 0.02,
    }));

    const draw = () => {
      raf = requestAnimationFrame(draw);
      frame++;

      const s = stateRef.current;
      const speed = s === "thinking" ? 2.8 : s === "responding" ? 1.6 : 1;
      const glow = s === "thinking" ? 0.18 + 0.12 * Math.sin(frame * 0.08) : s === "responding" ? 0.08 : 0;

      // Trailing clear
      ctx.fillStyle = "rgba(2, 2, 12, 0.18)";
      ctx.fillRect(0, 0, W, H);

      // Central pulse glow when thinking
      if (glow > 0) {
        const g = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, Math.min(W, H) * 0.55);
        g.addColorStop(0, `rgba(99,60,220,${glow})`);
        g.addColorStop(0.5, `rgba(60,40,180,${glow * 0.4})`);
        g.addColorStop(1, "rgba(0,0,0,0)");
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, W, H);
      }

      // Field lines
      for (const fl of lines) {
        for (let i = 0; i < fl.pts.length; i++) {
          fl.pts[i] += fl.vel[i] * speed;
          if (fl.pts[i] < -200 || fl.pts[i] > (i % 2 === 0 ? W : H) + 200) fl.vel[i] *= -1;
        }
        const [x0, y0, cx1, cy1, cx2, cy2, x1, y1] = fl.pts;
        const grad = ctx.createLinearGradient(x0, y0, x1, y1);
        const op = fl.opacity * (s === "thinking" ? 2.2 : s === "responding" ? 1.4 : 1);
        grad.addColorStop(0, `rgba(80,50,220,0)`);
        grad.addColorStop(0.5, `rgba(110,70,240,${op})`);
        grad.addColorStop(1, `rgba(80,50,220,0)`);
        ctx.beginPath();
        ctx.moveTo(x0, y0);
        ctx.bezierCurveTo(cx1, cy1, cx2, cy2, x1, y1);
        ctx.strokeStyle = grad;
        ctx.lineWidth = 1;
        ctx.stroke();
      }

      // Connections
      const maxDist = s === "thinking" ? 110 : 85;
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const d = Math.sqrt(dx * dx + dy * dy);
          if (d < maxDist) {
            const a = (1 - d / maxDist) * 0.12 * (s === "thinking" ? 2.5 : 1);
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(120,80,255,${a})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }
      }

      // Particles
      for (const p of particles) {
        p.x += p.vx * speed;
        p.y += p.vy * speed;
        p.phase += p.phaseSpeed * speed;
        if (p.x < 0) p.x = W;
        if (p.x > W) p.x = 0;
        if (p.y < 0) p.y = H;
        if (p.y > H) p.y = 0;

        const pulse = 0.5 + 0.5 * Math.sin(p.phase);
        const op = p.opacity * pulse * (s === "thinking" ? 1.5 : 1);
        const sz = p.size * (0.7 + 0.3 * pulse);

        // Soft glow
        const grd = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, sz * 5);
        grd.addColorStop(0, `rgba(${p.rgb},${op})`);
        grd.addColorStop(1, `rgba(${p.rgb},0)`);
        ctx.beginPath();
        ctx.arc(p.x, p.y, sz * 5, 0, Math.PI * 2);
        ctx.fillStyle = grd;
        ctx.fill();

        // Core
        ctx.beginPath();
        ctx.arc(p.x, p.y, sz, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${p.rgb},${Math.min(op * 2, 1)})`;
        ctx.fill();
      }

      // Arc sparks when thinking
      if (s === "thinking" && frame % 8 === 0) {
        const cx = W / 2 + (Math.random() - 0.5) * 60;
        const cy = H / 2 + (Math.random() - 0.5) * 60;
        ctx.beginPath();
        ctx.arc(cx, cy, Math.random() * 80 + 20, 0, Math.PI * 2 * Math.random());
        ctx.strokeStyle = `rgba(180,140,255,${Math.random() * 0.15})`;
        ctx.lineWidth = 0.5;
        ctx.stroke();
      }
    };

    draw();
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
    };
  }, []);

  return (
    <canvas
      ref={ref}
      style={{
        position: "fixed", inset: 0,
        width: "100%", height: "100%",
        zIndex: 0, pointerEvents: "none",
        background: "#02020c",
      }}
    />
  );
}
"}

{"content":""use client";

import styles from "./ConcentricCore.module.css";

const LAYERS = [
  { id: "aegis", name: "AEGIS", desc: "Governance Shell", color: "var(--sovereign-gold)" },
  { id: "aeon", name: "AEON", desc: "Cognitive OS", color: "var(--omega-cyan)" },
  { id: "adccl", name: "ADCCL", desc: "Control Loop", color: "var(--omega-blue)" },
  { id: "myelin", name: "MYELIN", desc: "Graph Memory", color: "var(--sovereign-orange)" },
];

export default function ConcentricCore() {
  return (
    <div className={styles.wrapper}>
      <div className={styles.container}>
        {LAYERS.map((layer, i) => (
          <div
            key={layer.id}
            className={styles.layer}
            style={{
              width: `${100 - i * 20}%`,
              height: `${100 - i * 20}%`,
              borderColor: layer.color,
              zIndex: 10 - i,
            }}
          >
            <div className={styles.label} style={{ color: layer.color }}>
              <span className={styles.layerName}>{layer.name}</span>
              <span className={styles.layerDesc}>{layer.desc}</span>
            </div>
          </div>
        ))}
      </div>
      <div className={styles.info}>
        <h2 className={styles.infoTitle}>Ωmegα Unified Architecture</h2>
        <p className={styles.infoText}>
          A four-layer concentric architecture solving memory, cognitive, runtime, and governance failure through a single unified system state.
        </p>
      </div>
    </div>
  );
}
"}

{"content":".wrapper {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4rem;
  align-items: center;
  margin: 4rem 0;
}

@media (max-width: 768px) {
  .wrapper {
    grid-template-columns: 1fr;
    text-align: center;
  }
}

.container {
  position: relative;
  width: 400px;
  height: 400px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: center;
}

@media (max-width: 480px) {
  .container {
    width: 280px;
    height: 280px;
  }
}

.layer {
  position: absolute;
  border: 2px solid;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
  background: rgba(0, 0, 0, 0.05);
  box-shadow: 0 0 20px rgba(0, 0, 0, 0.2);
}

.layer:hover {
  transform: scale(1.02);
  background: rgba(255, 255, 255, 0.02);
  box-shadow: 0 0 40px rgba(255, 255, 255, 0.05);
}

.label {
  position: absolute;
  top: 10px;
  display: flex;
  flex-direction: column;
  align-items: center;
  pointer-events: none;
  opacity: 0.6;
  transition: opacity 0.3s;
}

.layer:hover .label {
  opacity: 1;
}

.layerName {
  font-family: var(--font-mono);
  font-weight: 800;
  font-size: 0.8rem;
}

.layerDesc {
  font-size: 0.6rem;
  text-transform: uppercase;
  letter-spacing: 0.1em;
}

.infoTitle {
  font-size: 2.5rem;
  margin-bottom: 1.5rem;
  background: linear-gradient(to right, var(--omega-cyan), var(--sovereign-gold));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
}

.infoText {
  font-size: 1.1rem;
  color: #888;
  max-width: 500px;
}
"}

{"content":""use client";

import styles from "./SystemState.module.css";

const VARIABLES = [
  { symbol: "Φ", label: "Phylactery HEAD", desc: "Cryptographic hash of ratified identity" },
  { symbol: "E", label: "Active Run Envelope", desc: "Governance policy & tool manifest" },
  { symbol: "τ", label: "Task State Object", desc: "Structured representation of current task" },
  { symbol: "B", label: "Claim Budget", desc: "Evidence-paired assertions" },
  { symbol: "S", label: "Self-Tag", desc: "Immutable continuity record" },
  { symbol: "G", label: "Memory Graph", desc: "Utility-weighted MYELIN paths" },
];

export default function SystemState() {
  return (
    <div className={`${styles.container} glass`}>
      <h3 className={styles.title}>System State Vector (Ω<sub>t</sub>)</h3>
      <div className={styles.equation}>
        Ω<sub>t</sub> = ⟨
        {VARIABLES.map((v, i) => (
          <span key={v.symbol} className={styles.symbolWrapper}>
            <span className={styles.symbol}>{v.symbol}<sub>t</sub></span>
            {i < VARIABLES.length - 1 && <span className={styles.comma}>, </span>}
            <div className={styles.tooltip}>
              <strong>{v.label}</strong>
              <p>{v.desc}</p>
            </div>
          </span>
        ))}
        ⟩
      </div>
    </div>
  );
}
"}

{"content":".container {
  padding: 2.5rem;
  border-radius: 1.5rem;
  margin: 3rem 0;
  text-align: center;
  position: relative;
  overflow: visible;
}

.title {
  font-family: var(--font-mono);
  font-size: 1rem;
  color: #666;
  margin-bottom: 2rem;
  text-transform: uppercase;
  letter-spacing: 0.2em;
}

.equation {
  font-family: serif;
  font-style: italic;
  font-size: 2.5rem;
  color: #fff;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 0.2rem;
}

@media (max-width: 768px) {
  .equation {
    font-size: 1.5rem;
  }
}

.symbolWrapper {
  position: relative;
  cursor: help;
  display: inline-flex;
  align-items: center;
}

.symbol {
  color: var(--omega-cyan);
  transition: all 0.2s;
}

.symbolWrapper:hover .symbol {
  color: var(--sovereign-gold);
  text-shadow: 0 0 15px var(--sovereign-gold);
}

.comma {
  color: #444;
  margin-right: 0.3rem;
  font-style: normal;
}

.tooltip {
  position: absolute;
  bottom: 100%;
  left: 50%;
  transform: translateX(-50%) translateY(-10px);
  background: var(--obsidian);
  border: 1px solid var(--border-glass);
  padding: 1rem;
  border-radius: 0.5rem;
  width: 200px;
  font-family: var(--font-sans);
  font-style: normal;
  font-size: 0.85rem;
  opacity: 0;
  visibility: hidden;
  transition: all 0.2s;
  pointer-events: none;
  z-index: 50;
  text-align: left;
  box-shadow: 0 10px 30px rgba(0,0,0,0.5);
}

.symbolWrapper:hover .tooltip {
  opacity: 1;
  visibility: visible;
  transform: translateX(-50%) translateY(-20px);
}

.tooltip strong {
  display: block;
  color: var(--sovereign-gold);
  margin-bottom: 0.4rem;
}

.tooltip p {
  color: #999;
}
"}

{"content":""use client";

import { useEffect, useState } from "react";
import styles from "./IdentityShell.module.css";

const BANNER = [
    "    ██████╗     ██╗    ██╗    ███████╗    ██╗   ██╗",
    "    ██╔══██╗    ██║    ██║    ██╔════╝    ╚██╗ ██╔╝",
    "    ██████╔╝    ██║ █╗ ██║    █████╗       ╚████╔╝ ",
    "    ██╔══██╗    ██║███╗██║    ██╔══╝        ╚██╔╝  ",
    "    ██║  ██║    ╚███╔███╔╝    ██║            ██║   ",
    "    ╚═╝  ╚═╝     ╚══╝╚══╝     ╚═╝            ╚═╝   "
];

export default function IdentityShell() {
  const [offset, setOffset] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setOffset((prev) => (prev + 0.01) % 1.0);
    }, 50);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className={styles.container}>
      <pre className={styles.banner}>
        {BANNER.map((line, i) => (
          <div key={i} className={styles.line}>
            {line.split("").map((char, x) => (
              <span
                key={x}
                style={{
                  color: char === "█" ? "#282d32" : `hsl(${(x * 2 + i * 5 + offset * 360) % 360}, 100%, 70%)`,
                  opacity: char === " " ? 0 : 1,
                  textShadow: char !== "█" && char !== " " ? `0 0 10px hsla(${(x * 2 + i * 5 + offset * 360) % 360}, 100%, 70%, 0.5)` : "none"
                }}
              >
                {char}
              </span>
            ))}
          </div>
        ))}
      </pre>
      <div className={styles.meta}>
        <span className={styles.title}>THE OMEGA SOVEREIGN PORTAL</span>
        <span className={styles.subtitle}>(YETTRAGRAMMATON)</span>
      </div>
    </div>
  );
}
"}

